package main

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"slices"
	"strings"
	"testing"
)

// minimalPDF returns the bytes of a valid minimal PDF where each page has an
// uncompressed content stream containing a comment with the given label.
// Labels appear literally in the raw bytes and survive pdfcpu merge/split.
func minimalPDF(labels []string) []byte {
	pageCount := len(labels)
	var buf bytes.Buffer
	// Objects: 1=Catalog, 2=Pages, then per page: (page obj, content obj)
	numObjs := 2 + 2*pageCount
	offsets := make([]int, numObjs)

	w := func(s string) { buf.WriteString(s) }
	wf := func(format string, args ...any) { fmt.Fprintf(&buf, format, args...) }
	startObj := func(n int) {
		offsets[n-1] = buf.Len()
		wf("%d 0 obj\n", n)
	}
	endObj := func() { w("endobj\n") }

	w("%PDF-1.4\n")

	startObj(1)
	w("<< /Type /Catalog /Pages 2 0 R >>\n")
	endObj()

	// Page objects are at 3, 5, 7, ... (odd); content streams at 4, 6, 8, ... (even)
	var kids strings.Builder
	for i := range pageCount {
		if i > 0 {
			kids.WriteByte(' ')
		}
		fmt.Fprintf(&kids, "%d 0 R", 3+i*2)
	}
	startObj(2)
	wf("<< /Type /Pages /Kids [%s] /Count %d >>\n", kids.String(), pageCount)
	endObj()

	for i, label := range labels {
		pageObjN := 3 + i*2
		contObjN := 4 + i*2
		stream := fmt.Sprintf("%% %s\n", label) // PDF comment; appears literally in raw bytes

		startObj(pageObjN)
		wf("<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents %d 0 R >>\n", contObjN)
		endObj()

		startObj(contObjN)
		wf("<< /Length %d >>\n", len(stream))
		w("stream\n")
		w(stream)
		w("endstream\n")
		endObj()
	}

	xrefOff := buf.Len()
	xrefCount := numObjs + 1 // +1 for free object 0
	wf("xref\n0 %d\n", xrefCount)
	wf("0000000000 65535 f\r\n")
	for _, off := range offsets {
		wf("%010d 00000 n\r\n", off)
	}
	wf("trailer\n<< /Size %d /Root 1 0 R >>\n", xrefCount)
	wf("startxref\n%d\n", xrefOff)
	w("%%EOF\n")

	return buf.Bytes()
}

func writePDF(t *testing.T, path string, labels []string) {
	t.Helper()
	if err := os.WriteFile(path, minimalPDF(labels), 0o644); err != nil {
		t.Fatal(err)
	}
}

// labelPositions returns the byte offset of each label in data, or -1 if absent.
func labelPositions(data []byte, labels []string) []int {
	pos := make([]int, len(labels))
	for i, l := range labels {
		pos[i] = bytes.Index(data, []byte(l))
	}
	return pos
}

// assertOrder checks that the given labels appear in data in the given order.
func assertOrder(t *testing.T, data []byte, ordered []string) {
	t.Helper()
	pos := labelPositions(data, ordered)
	for i, p := range pos {
		if p == -1 {
			t.Errorf("label %q not found in output", ordered[i])
		}
	}
	for i := 1; i < len(pos); i++ {
		if pos[i-1] >= pos[i] {
			t.Errorf("label %q (pos %d) should appear before %q (pos %d)",
				ordered[i-1], pos[i-1], ordered[i], pos[i])
		}
	}
}

// --- interleave unit tests ---

func TestInterleaveEqual(t *testing.T) {
	got := interleave([]string{"A", "B", "C"}, []string{"X", "Y", "Z"})
	want := []string{"A", "X", "B", "Y", "C", "Z"}
	if !slices.Equal(got, want) {
		t.Errorf("got %v, want %v", got, want)
	}
}

func TestInterleaveFirstLonger(t *testing.T) {
	got := interleave([]string{"A", "B", "C", "D"}, []string{"X", "Y"})
	want := []string{"A", "X", "B", "Y", "C", "D"}
	if !slices.Equal(got, want) {
		t.Errorf("got %v, want %v", got, want)
	}
}

func TestInterleaveSecondLonger(t *testing.T) {
	got := interleave([]string{"A"}, []string{"X", "Y", "Z"})
	want := []string{"A", "X", "Y", "Z"}
	if !slices.Equal(got, want) {
		t.Errorf("got %v, want %v", got, want)
	}
}

func TestInterleaveFirstEmpty(t *testing.T) {
	got := interleave([]string{}, []string{"X", "Y"})
	want := []string{"X", "Y"}
	if !slices.Equal(got, want) {
		t.Errorf("got %v, want %v", got, want)
	}
}

func TestInterleaveBothEmpty(t *testing.T) {
	got := interleave([]string{}, []string{})
	if len(got) != 0 {
		t.Errorf("got %v, want empty slice", got)
	}
}

// --- Merge tests ---

func TestMergePDFs(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	if err := mergePDFs(fileA, fileB, out, true, false, nil, nil); err != nil {
		t.Fatal(err)
	}

	if count, err := pdfPageCount(out); err != nil {
		t.Fatal(err)
	} else if count != 6 {
		t.Errorf("got %d pages, want 6", count)
	}

	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"A1", "B1", "A2", "B2", "A3", "B3"})
}

func TestMergePDFsFirstPageInB(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	if err := mergePDFs(fileA, fileB, out, false, false, nil, nil); err != nil {
		t.Fatal(err)
	}

	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"B1", "A1", "B2", "A2", "B3", "A3"})
}

func TestMergePDFsReverseB(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	if err := mergePDFs(fileA, fileB, out, true, true, nil, nil); err != nil {
		t.Fatal(err)
	}

	if count, err := pdfPageCount(out); err != nil {
		t.Fatal(err)
	} else if count != 6 {
		t.Errorf("got %d pages, want 6", count)
	}

	// reverseB reverses file B: B3, B2, B1 → output: A1,B3, A2,B2, A3,B1
	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"A1", "B3", "A2", "B2", "A3", "B1"})
}

func TestMergePDFsUnequalCounts(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3", "A4"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	if err := mergePDFs(fileA, fileB, out, true, false, nil, nil); err != nil {
		t.Fatal(err)
	}

	// 3 interleaved pairs + 1 extra A page = 7
	if count, err := pdfPageCount(out); err != nil {
		t.Fatal(err)
	} else if count != 7 {
		t.Errorf("got %d pages, want 7", count)
	}

	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"A1", "B1", "A2", "B2", "A3", "B3", "A4"})
}

func TestMergePDFsSkip(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	// Skip A page 2 and B page 1 → A=[A1,A3], B=[B2,B3] → interleaved: A1,B2, A3,B3
	if err := mergePDFs(fileA, fileB, out, true, false, []int{2}, []int{1}); err != nil {
		t.Fatal(err)
	}

	if count, err := pdfPageCount(out); err != nil {
		t.Fatal(err)
	} else if count != 4 {
		t.Errorf("got %d pages, want 4", count)
	}

	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"A1", "B2", "A3", "B3"})
	if bytes.Contains(data, []byte("A2")) {
		t.Error("skipped page A2 found in output")
	}
	if bytes.Contains(data, []byte("B1")) {
		t.Error("skipped page B1 found in output")
	}
}

// --- Split tests ---

func TestSplitPDF(t *testing.T) {
	tmp := t.TempDir()
	in := filepath.Join(tmp, "input.pdf")
	outDir := filepath.Join(tmp, "out")
	if err := os.MkdirAll(outDir, 0o755); err != nil {
		t.Fatal(err)
	}

	writePDF(t, in, []string{"P1", "P2", "P3", "P4", "P5", "P6"})

	// Split after pages 2 and 4 → three files: 1-2, 3-4, 5-6
	parts, err := splitPDF(in, []int{2, 4}, outDir)
	if err != nil {
		t.Fatal(err)
	}

	if len(parts) != 3 {
		t.Fatalf("got %d parts, want 3", len(parts))
	}

	for i, want := range []int{2, 2, 2} {
		if got, err := pdfPageCount(parts[i]); err != nil {
			t.Fatalf("part %d: %v", i, err)
		} else if got != want {
			t.Errorf("part %d: got %d pages, want %d", i, got, want)
		}
	}

	for i, labels := range [][]string{{"P1", "P2"}, {"P3", "P4"}, {"P5", "P6"}} {
		data, err := os.ReadFile(parts[i])
		if err != nil {
			t.Fatal(err)
		}
		assertOrder(t, data, labels)
	}
}

func TestSplitPDFSingleOutput(t *testing.T) {
	tmp := t.TempDir()
	in := filepath.Join(tmp, "input.pdf")
	outDir := filepath.Join(tmp, "out")
	if err := os.MkdirAll(outDir, 0o755); err != nil {
		t.Fatal(err)
	}

	writePDF(t, in, []string{"P1", "P2", "P3", "P4"})

	parts, err := splitPDF(in, nil, outDir)
	if err != nil {
		t.Fatal(err)
	}

	if len(parts) != 1 {
		t.Fatalf("got %d parts, want 1", len(parts))
	}

	if got, err := pdfPageCount(parts[0]); err != nil {
		t.Fatal(err)
	} else if got != 4 {
		t.Errorf("got %d pages, want 4", got)
	}
}

package main

import (
	"context"
	"encoding/base64"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"

	"github.com/wailsapp/wails/v2/pkg/runtime"
)

// App struct
type App struct {
	ctx context.Context
}

// NewApp creates a new App application struct
func NewApp() *App {
	return &App{}
}

// startup is called when the app starts. The context is saved
// so we can call the runtime methods
func (a *App) startup(ctx context.Context) {
	a.ctx = ctx
}

// OpenPDF shows a file-open dialog filtered to PDFs and returns the selected path.
// Returns an empty string if the user cancels.
func (a *App) OpenPDF() (string, error) {
	path, err := runtime.OpenFileDialog(a.ctx, runtime.OpenDialogOptions{
		Title: "Open PDF",
		Filters: []runtime.FileFilter{
			{DisplayName: "PDF Files (*.pdf)", Pattern: "*.pdf"},
		},
	})
	return path, err
}

// PageCount returns the number of pages in the PDF at path.
func (a *App) PageCount(path string) (int, error) {
	return pdfPageCount(path)
}

// RenderPage renders a single page of the PDF at path as a PNG and returns it
// base64-encoded. widthPx controls the output width; height is scaled proportionally.
func (a *App) RenderPage(path string, pageNum int, widthPx int) (string, error) {
	tmpDir, err := os.MkdirTemp("", "psp-render-*")
	if err != nil {
		return "", err
	}
	defer os.RemoveAll(tmpDir)

	outPrefix := filepath.Join(tmpDir, "page")
	page := strconv.Itoa(pageNum)

	out, err := exec.Command(
		"pdftoppm",
		"-f", page,
		"-l", page,
		"-singlefile",
		"-png",
		"-scale-to-x", strconv.Itoa(widthPx),
		"-scale-to-y", "-1",
		path,
		outPrefix,
	).CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("pdftoppm: %w\n%s", err, out)
	}

	data, err := os.ReadFile(outPrefix + ".png")
	if err != nil {
		return "", err
	}
	return base64.StdEncoding.EncodeToString(data), nil
}

// SavePDF shows a save-file dialog filtered to PDFs and returns the chosen path.
// Returns an empty string if the user cancels.
func (a *App) SavePDF() (string, error) {
	path, err := runtime.SaveFileDialog(a.ctx, runtime.SaveDialogOptions{
		Title:           "Save Merged PDF",
		DefaultFilename: "merged.pdf",
		Filters: []runtime.FileFilter{
			{DisplayName: "PDF Files (*.pdf)", Pattern: "*.pdf"},
		},
	})
	if err != nil || path == "" {
		return path, err
	}
	if !strings.HasSuffix(strings.ToLower(path), ".pdf") {
		path += ".pdf"
	}
	return path, nil
}

// MergePDFs interleaves pages from frontPath and backPath and writes the result to outPath.
func (a *App) MergePDFs(pathA, pathB, outPath string, firstPageInA, reverseB bool, skipA, skipB []int) error {
	return mergePDFs(pathA, pathB, outPath, firstPageInA, reverseB, skipA, skipB)
}

package main

import (
	"fmt"
	"io"
	"os"
	"path/filepath"
	"slices"
	"sort"
	"strings"

	"github.com/pdfcpu/pdfcpu/pkg/api"
)

// mergePDFs interleaves pages from pathA and pathB into outPath.
// If firstPageInA is true, file A contributes the odd-numbered output pages (1, 3, 5, …);
// otherwise file B does. If reverseB is true, file B's pages are reversed before interleaving,
// which is the typical case when the paper stack was flipped between scans.
// If the page counts differ, the extra pages from the longer file are
// appended in order after the interleaved section.
func mergePDFs(pathA, pathB, outPath string, firstPageInA, reverseB bool, skipA, skipB []int) error {
	tmpDir, err := os.MkdirTemp("", "psp-merge-*")
	if err != nil {
		return err
	}
	defer os.RemoveAll(tmpDir)

	dirA := filepath.Join(tmpDir, "a")
	dirB := filepath.Join(tmpDir, "b")
	for _, d := range []string{dirA, dirB} {
		if err := os.MkdirAll(d, 0o755); err != nil {
			return err
		}
	}

	if err := api.SplitFile(pathA, dirA, 1, nil); err != nil {
		return fmt.Errorf("splitting file A: %w", err)
	}
	if err := api.SplitFile(pathB, dirB, 1, nil); err != nil {
		return fmt.Errorf("splitting file B: %w", err)
	}

	pagesA, err := sortedPDFsInDir(dirA)
	if err != nil {
		return fmt.Errorf("listing file A pages: %w", err)
	}
	pagesB, err := sortedPDFsInDir(dirB)
	if err != nil {
		return fmt.Errorf("listing file B pages: %w", err)
	}

	pagesA = filterSkipped(pagesA, skipA)
	pagesB = filterSkipped(pagesB, skipB)
	if reverseB {
		slices.Reverse(pagesB)
	}

	if firstPageInA {
		return api.MergeCreateFile(interleave(pagesA, pagesB), outPath, false, nil)
	}
	return api.MergeCreateFile(interleave(pagesB, pagesA), outPath, false, nil)
}

func filterSkipped(pages []string, skip []int) []string {
	if len(skip) == 0 {
		return pages
	}
	skipSet := make(map[int]bool, len(skip))
	for _, p := range skip {
		skipSet[p] = true
	}
	out := make([]string, 0, len(pages))
	for i, p := range pages {
		if !skipSet[i+1] {
			out = append(out, p)
		}
	}
	return out
}

// splitPDF splits the PDF at inPath at the given page boundaries and writes
// each segment to outDir, returning the output file paths in order.
// splitAfter contains 1-indexed page numbers after which a new file begins.
// E.g. splitAfter=[2,4] on a 6-page PDF produces three files: pages 1-2, 3-4, 5-6.
func splitPDF(inPath string, splitAfter []int, outDir string) ([]string, error) {
	if len(splitAfter) == 0 {
		outPath := filepath.Join(outDir, filepath.Base(inPath))
		if err := copyFile(inPath, outPath); err != nil {
			return nil, err
		}
		return []string{outPath}, nil
	}

	// SplitByPageNrFile expects the first page of each new segment.
	pageNrs := make([]int, len(splitAfter))
	for i, p := range splitAfter {
		pageNrs[i] = p + 1
	}

	if err := api.SplitByPageNrFile(inPath, outDir, pageNrs, nil); err != nil {
		return nil, fmt.Errorf("splitting PDF: %w", err)
	}

	return sortedPDFsInDir(outDir)
}

// pdfPageCount returns the number of pages in the PDF at path.
func pdfPageCount(path string) (int, error) {
	return api.PageCountFile(path)
}

// sortedPDFsInDir lists PDF files in dir sorted numerically by the first page
// number encoded in pdfcpu's output filenames (e.g. "doc_3-5.pdf" → 3).
func sortedPDFsInDir(dir string) ([]string, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return nil, err
	}
	type item struct {
		path     string
		fromPage int
	}
	var files []item
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(strings.ToLower(e.Name()), ".pdf") {
			continue
		}
		files = append(files, item{
			path:     filepath.Join(dir, e.Name()),
			fromPage: pdfFromPage(e.Name()),
		})
	}
	sort.Slice(files, func(i, j int) bool { return files[i].fromPage < files[j].fromPage })
	result := make([]string, len(files))
	for i, f := range files {
		result[i] = f.path
	}
	return result, nil
}

// interleave merges two slices by alternating elements: a[0], b[0], a[1], b[1], ...
// If the slices have different lengths, the remaining elements of the longer
// slice are appended in order after the interleaved section.
func interleave[T any](a, b []T) []T {
	n := min(len(a), len(b))
	out := make([]T, 0, len(a)+len(b))
	for i := range n {
		out = append(out, a[i], b[i])
	}
	out = append(out, a[n:]...)
	out = append(out, b[n:]...)
	return out
}

func copyFile(src, dst string) error {
	in, err := os.Open(src)
	if err != nil {
		return err
	}
	defer in.Close()
	out, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer out.Close()
	_, err = io.Copy(out, in)
	return err
}

// pdfFromPage extracts the first page number from a pdfcpu split filename
// such as "doc_1.pdf" or "doc_3-5.pdf".
func pdfFromPage(name string) int {
	name = strings.TrimSuffix(name, ".pdf")
	parts := strings.Split(name, "_")
	if len(parts) == 0 {
		return 0
	}
	rangeStr := parts[len(parts)-1]
	n := 0
	fmt.Sscanf(strings.SplitN(rangeStr, "-", 2)[0], "%d", &n)
	return n
}

