          onWidthChange={setTotalWidth}
          colWidth={colWidth}
          reverseB={reverseB}
          skippedA={skippedA}
          skippedB={skippedB}
          onToggleSkip={toggleSkip}
        />
        {selectedPath && (
          <DetailPanel
            pdfPath={selectedPath}
            pageNum={selectedPage.page}
            pageCount={selectedCount}
            onNavigate={(page) => setSelectedPage({ file: selectedPage.file, page })}
            onToggleSkip={() => toggleSkip(selectedPage.file, selectedPage.page)}
          />
        )}
      </Box>
    </Box>
  )
}

function FilePickerColumn({
  label, path, width, onChoose,
}: {
  label: string
  path: string | null
  width: number
  onChoose: () => void
}) {
  return (
    <Box
      style={{
        width,
        flexShrink: 0,
        padding: '6px 8px',
        borderRight: '1px solid var(--mantine-color-gray-3)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        gap: 2,
      }}
    >
      <Group justify="space-between" gap={4} wrap="nowrap">
        <Text size="xs" c="dimmed">{label}</Text>
        <Button size="xs" variant="default" onClick={onChoose}>Choose…</Button>
      </Group>
      <Text
        size="xs"
        style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        title={path ?? undefined}
      >
        {path ? basename(path) : '—'}
      </Text>
    </Box>
  )
}

