func TestMergePDFsRotate(t *testing.T) {
	tmp := t.TempDir()
	fileA := filepath.Join(tmp, "a.pdf")
	fileB := filepath.Join(tmp, "b.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, fileA, []string{"A1", "A2", "A3"})
	writePDF(t, fileB, []string{"B1", "B2", "B3"})

	// Rotate A page 2 by 90° and B page 1 by 180°
	rotA := map[int]int{2: 90}
	rotB := map[int]int{1: 180}

	if err := mergePDFs(fileA, fileB, out, true, false, nil, nil, rotA, rotB); err != nil {
		t.Fatal(err)
	}

	if count, err := pdfPageCount(out); err != nil {
		t.Fatal(err)
	} else if count != 6 {
		t.Errorf("got %d pages, want 6", count)
	}

	// Page order is still correct
	data, err := os.ReadFile(out)
	if err != nil {
		t.Fatal(err)
	}
	assertOrder(t, data, []string{"A1", "B1", "A2", "B2", "A3", "B3"})

	// PDF page dicts are stored as plain text, so /Rotate values appear literally
	if !bytes.Contains(data, []byte("/Rotate 90")) {
		t.Error("expected /Rotate 90 in output (A page 2 rotated)")
	}
	if !bytes.Contains(data, []byte("/Rotate 180")) {
		t.Error("expected /Rotate 180 in output (B page 1 rotated)")
	}
	// Unrotated pages must not introduce spurious /Rotate entries
	// (count occurrences: exactly one 90 and one 180)
	if bytes.Count(data, []byte("/Rotate 90")) != 1 {
		t.Error("expected exactly one /Rotate 90 entry")
	}
	if bytes.Count(data, []byte("/Rotate 180")) != 1 {
		t.Error("expected exactly one /Rotate 180 entry")
	}
}

// --- Split tests ---

